package com.example.app;

import android.content.Context;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricManager;

public final class BiometricGate {
    private BiometricGate() {}

    public static boolean canUseBiometrics(@NonNull Context context) {
        BiometricManager bm = BiometricManager.from(context);
        int res = bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);
        return res == BiometricManager.BIOMETRIC_SUCCESS;
    }

    public static int biometricStatus(@NonNull Context context) {
        BiometricManager bm = BiometricManager.from(context);
        return bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG);
    }
}

package com.example.app;

import android.app.Activity;

import androidx.annotation.NonNull;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.FragmentActivity;

import java.util.concurrent.Executor;

public final class BiometricAuth {
    public interface Callback {
        void onSuccess();
        void onFailure();
        void onError(int errorCode, @NonNull CharSequence errString);
    }

    private BiometricAuth() {}

    public static void authenticate(@NonNull FragmentActivity activity,
                                    @NonNull String title,
                                    @NonNull String subtitle,
                                    @NonNull String negativeText,
                                    @NonNull Callback callback) {
        Executor executor = ContextCompat.getMainExecutor(activity);

        BiometricPrompt.AuthenticationCallback authCallback = new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                callback.onSuccess();
            }

            @Override
            public void onAuthenticationFailed() {
                callback.onFailure();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                callback.onError(errorCode, errString);
            }
        };

        BiometricPrompt prompt = new BiometricPrompt(activity, executor, authCallback);

        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setAllowedAuthenticators(androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG)
                .setNegativeButtonText(negativeText)
                .build();

        prompt.authenticate(promptInfo);
    }
}

package com.example.app;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class LauncherActivity extends AppCompatActivity {

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (AuthPrefs.isLoggedIn(this)) {
            startActivity(new Intent(this, MainActivity.class));
            finish();
            return;
        }

        if (AuthPrefs.isBiometricEnabled(this) && BiometricGate.canUseBiometrics(this)) {
            BiometricAuth.authenticate(
                    this,
                    "Unlock",
                    "Authenticate with your fingerprint",
                    "Use password",
                    new BiometricAuth.Callback() {
                        @Override
                        public void onSuccess() {
                            AuthPrefs.setLoggedIn(LauncherActivity.this, true);
                            startActivity(new Intent(LauncherActivity.this, MainActivity.class));
                            finish();
                        }

                        @Override
                        public void onFailure() {
                        }

                        @Override
                        public void onError(int errorCode, CharSequence errString) {
                            startActivity(new Intent(LauncherActivity.this, LoginActivity.class));
                            finish();
                        }
                    }
            );
        } else {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
        }
    }
}

package com.example.app;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.Button;
import android.widget.CheckBox;
import android.widget.EditText;
import android.widget.LinearLayout;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText etPassword;
    private CheckBox cbEnableBiometric;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int pad = (int) (16 * getResources().getDisplayMetrics().density);
        root.setPadding(pad, pad, pad, pad);

        etPassword = new EditText(this);
        etPassword.setHint("Password");
        etPassword.setInputType(android.text.InputType.TYPE_CLASS_TEXT | android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD);

        cbEnableBiometric = new CheckBox(this);
        cbEnableBiometric.setText("Enable biometric login");
        cbEnableBiometric.setChecked(AuthPrefs.isBiometricEnabled(this));
        cbEnableBiometric.setEnabled(BiometricGate.canUseBiometrics(this));

        Button btnLogin = new Button(this);
        btnLogin.setText("Login");

        root.addView(etPassword);
        root.addView(cbEnableBiometric);
        root.addView(btnLogin);

        setContentView(root);

        btnLogin.setOnClickListener(v -> {
            String pwd = etPassword.getText() == null ? "" : etPassword.getText().toString();
            if (!validatePassword(pwd)) {
                etPassword.setError("Invalid password");
                return;
            }

            AuthPrefs.setLoggedIn(this, true);

            boolean enableBio = cbEnableBiometric.isChecked() && BiometricGate.canUseBiometrics(this);
            AuthPrefs.setBiometricEnabled(this, enableBio);

            startActivity(new Intent(this, MainActivity.class));
            finish();
        });
    }

    private boolean validatePassword(String pwd) {
        return !TextUtils.isEmpty(pwd) && pwd.length() >= 4;
    }
}

